mapper.select:
SELECT lot_num, lot_code, item_name, code, current_qty, lot_date, lot_status, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT l.lot_num, l.lot_code, i.name AS item_name, i.code, l.current_qty, l.lot_date, l.lot_status, COUNT(*) OVER() AS total_count FROM lot l LEFT JOIN item i ON l.item_num = i.item_num
AND l.lot_date >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND l.lot_date <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND l.lot_status = #{lot_status}
AND l.item_num = #{item_num}
AND (l.lot_code LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
ORDER BY l.lot_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}
